package com.nexra.hrms.nexra.modules.hrms.performance.entity.base; import jakarta.persistence.*; import java.time.Instant; import org.springframework.data.annotation.*; import org.springframework.data.jpa.domain.support.AuditingEntityListener;
@MappedSuperclass @EntityListeners(AuditingEntityListener.class) public abstract class AbstractAuditableEntity { @CreatedDate @Column(name="created_at",nullable=false,updatable=false) private Instant createdAt; @LastModifiedDate @Column(name="updated_at",nullable=false) private Instant updatedAt; @Column(name="created_by",nullable=false,length=120) private String createdBy; @Column(name="updated_by",nullable=false,length=120) private String updatedBy; public Instant getCreatedAt(){return createdAt;} public Instant getUpdatedAt(){return updatedAt;} public String getCreatedBy(){return createdBy;} public void setCreatedBy(final String v){createdBy=v;} public String getUpdatedBy(){return updatedBy;} public void setUpdatedBy(final String v){updatedBy=v;} }

